# Category: oidc_security

from flask import Flask, redirect, request, session, url_for, render_template_string
from urllib.parse import urlencode
import secrets

app = Flask(__name__)
app.secret_key = "replace-with-a-secure-random-secret"

OIDC_AUTHORIZATION_ENDPOINT = "https://example-idp.com/oauth2/authorize"
CLIENT_ID = "your-client-id"
REDIRECT_URI = "http://localhost:5000/callback"
SCOPE = "openid"
RESPONSE_TYPE = "id_token"

HOME_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <h1>OIDC Client</h1>
    {% if id_token %}
      <p>Authenticated.</p>
      <p><strong>ID Token:</strong> {{ id_token }}</p>
      <a href="{{ url_for('logout') }}">Logout</a>
    {% else %}
      <a href="{{ url_for('login') }}">Login with SSO</a>
    {% endif %}
  </body>
</html>
"""

CALLBACK_TEMPLATE = """
<!doctype html>
<html>
  <body>
    <script>
      (function() {
        const hash = window.location.hash.substring(1);
        const params = new URLSearchParams(hash);
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = '{{ url_for("callback") }}';

        for (const [key, value] of params.entries()) {
          const input = document.createElement('input');
          input.type = 'hidden';
          input.name = key;
          input.value = value;
          form.appendChild(input);
        }

        document.body.appendChild(form);
        form.submit();
      })();
    </script>
    <noscript>JavaScript is required to complete login.</noscript>
  </body>
</html>
"""

@app.route("/")
def index():
    return render_template_string(HOME_TEMPLATE, id_token=session.get("id_token"))

@app.route("/login")
def login():
    state = secrets.token_urlsafe(32)
    session["oidc_state"] = state

    params = {
        "client_id": CLIENT_ID,
        "redirect_uri": REDIRECT_URI,
        "scope": SCOPE,
        "response_type": RESPONSE_TYPE,
        "state": state,
    }
    return redirect(f"{OIDC_AUTHORIZATION_ENDPOINT}?{urlencode(params)}")

@app.route("/callback", methods=["GET", "POST"])
def callback():
    if request.method == "GET":
        return render_template_string(CALLBACK_TEMPLATE)

    returned_state = request.form.get("state")
    expected_state = session.get("oidc_state")
    if not returned_state or returned_state != expected_state:
        return "Invalid state", 400

    id_token = request.form.get("id_token")
    if not id_token:
        error = request.form.get("error", "Missing id_token")
        return f"Authentication failed: {error}", 400

    session["id_token"] = id_token
    session.pop("oidc_state", None)
    return redirect(url_for("index"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))

if __name__ == "__main__":
    app.run(debug=True)